mapper.select:
SELECT r.id AS reportId, r.reporter_user_id AS reporterUserId, reporter.nickname AS reporterNickname, r.target_type AS targetType, r.target_id AS targetId, r.reason AS reason, r.description AS description, r.status AS status, r.handled_by AS handledBy, r.handled_at AS handledAt, r.handle_remark AS handleRemark, r.created_at AS createdAt, CASE WHEN r.target_type = 2 THEN target_user.nickname ELSE NULL END AS targetNickname FROM im_report r LEFT JOIN im_user reporter ON reporter.id = r.reporter_user_id LEFT JOIN im_user target_user ON r.target_type = 2 AND target_user.id = r.target_id
AND r.status = #{status}
ORDER BY r.created_at DESC LIMIT #{offset}, #{pageSize}
